SELECT id, template_id, message_type, receiver_id, receiver_address, subject, content, send_status, send_time, error_message, created_time FROM msg_record WHERE deleted = FALSE
AND message_type = #{messageType}
AND send_status = #{sendStatus}
AND receiver_id = #{receiverId}
ORDER BY created_time DESC
